import { viewportProjection } from '@cornerstonejs/core';
export function getViewportPresentation(viewport, selector) {
    const projectionPresentation = viewportProjection.getPresentation(viewport, {
        selector,
    });
    if (projectionPresentation) {
        return projectionPresentation;
    }
    return viewport.getViewPresentation?.(selector);
}
export function applyViewportPresentation(viewport, presentation) {
    if (!presentation) {
        return false;
    }
    const target = viewport;
    const nextViewState = viewportProjection.withPresentation(viewport, presentation);
    if (nextViewState && typeof target.setViewState === 'function') {
        target.setViewState(nextViewState);
        return true;
    }
    if (typeof target.setViewPresentation === 'function') {
        target.setViewPresentation(presentation);
        return true;
    }
    return false;
}
